MultiLanguageSpellData['ko'][471365] = {name = "언더마인", additional_info = "즉시\n[q]권장 숙련도: 375\n\n 각종 배관을 타고 스팀휘들 유출물이 졸졸 흐릅니다. 이런 수역에서 살 수 있는 건 무엇보다 튼튼한 카즈 알가르 물고기와 지독한 액체를 견뎌낼 수 있는 존재들 뿐입니다.\n\n 이 지역의 웅덩이\n - 아른웅덩이\n - 마력 깃든 수액\n - 스팀휘들 유출물\n전문 기술:\n낚시 (225)"}
