MultiLanguageSpellData['ko'][471927] = {name = "옭아매는 불길", additional_info = "100 야드 사정거리\n즉시\n[q]굴림판 도우미가 플레이어를 불길로 휘감아 30초 동안 1초마다 1844719의 화염 피해를 입힙니다. 이 지옥불은 피해를 입힐 때마다 대상의 최대 생명력을 5%만큼 감소시킵니다.\n\n 효과가 제거되면 움직이는 불꽃 |1이;가; 플레이어 바깥쪽으로 분출됩니다."}
