MultiLanguageSpellData['ko'][1218304] = {name = "시험용 자동 홍보기", additional_info = "100 야드 사정거리\n즉시\n[q]자동 홍보기를 설치해 주위의 모든 생명체를 극도로 짜증 나게 만들고 3분 동안 자신에게 입히는 피해를 50%만큼 증가시킵니다.\n\n 언더마인에서만 사용할 수 있습니다. 활성화된 동안 적이 시전자를 위한 시장 연구 자료를 추가로 제공합니다."}
MultiLanguageSpellData['ko'][1218305] = {name = "공허로 단련된 군마", additional_info = "1.5 초 주문 시전 시간\n[q]탈것에 올라타거나 내립니다.\n[q]\"한때 착용했던 편자처럼 다시 벼려내진 야수입니다. 이젠 말보단 공허 마력으로 이루어진 생명체에 가깝습니다.\"\n획득:\n지역:\n다시 찾은 스톰윈드의 환영"}
MultiLanguageSpellData['ko'][1218306] = {name = "공허의 자취가 남은 무리 어미", additional_info = "1.5 초 주문 시전 시간\n[q]탈것에 올라타거나 내립니다.\n[q]\"이 무리 어미는 타락한 조련사들을 무찌른 뒤 자식들을 데리고 빠져나왔습니다. 하지만 이 버려진 장소에서는 조련사에서 벗어난다고 한들 진정한 공허로부터의 자유를 의미하진 않았습니다. 무리 어미는 자식들을 위험한 야수로 길러냈고, 이젠 오그리마 곳곳을 떠돌며 살아남는 데 필요한 식량을 구하고 있습니다.\"\n획득:\n지역:\n다시 찾은 오그리마의 환영"}
MultiLanguageSpellData['ko'][1218307] = {name = "공허의 자취가 남은 와이번", additional_info = "1.5 초 주문 시전 시간\n[q]탈것에 올라타거나 내립니다.\n[q]\"공허 마력이 방출될 때 와이번 대부분은 이성을 잃고 날뛰었습니다. 동족은 물론 조련사까지 닥치는 대로 살육을 벌였죠. 둥지로 통하는 관문은 생존자들이 걸어 잠갔습니다. 몇몇 살아남은 와이번이 하늘 위를 날아다니는 모습이 보이곤 하지만, 죽음의 영역이 되어버린 와이번의 둥지로 가보려는 한 명도 이는 없습니다.\"\n획득:\n지역:\n다시 찾은 오그리마의 환영"}
MultiLanguageSpellData['ko'][1218308] = {name = "타오르는 지옥불", additional_info = "즉시\n[q]블레지콘이 꺼진 양초 방향으로 이글거리는 불길을 방출해 양초를 다시 밝히고 경로상의 모든 플레이어에게 8487876의 화염 피해를 입힙니다.\n\n 이 지옥불은 모든 플레이어를 그슬리게 만들어 8초 동안 1초마다 242445의 화염 피해를 입힙니다. 이 효과는 중첩됩니다."}
MultiLanguageSpellData['ko'][1218310] = {name = "전기침 시험 모델", additional_info = "30 야드 사정거리2 초 주문 시전 시간 10 분 재사용 대기시간\n[q]대상에게 활력의 전압을 흘려보내 가속을 20%만큼 증가시키고 받는 피해는 25%만큼 감소시킵니다. 또한 3분 동안 자연 피해를 입히는 파동을 방출하게 합니다.\n\n 언더마인에 있는 거의 모든 희귀 생명체에게 사용할 수 있습니다. 활성화된 동안 대상은 모든 플레이어에게 시장 연구 자료를 추가로 제공합니다."}
