MultiLanguageSpellData['ko'][1234351] = {name = "비전의 감화", additional_info = "즉시\n[q]유물 능력\n\n 바깥쪽으로 뻗어나갔다가 시전자 방향으로 돌아오는 비전 마력 원반을 던집니다.\n\n나란의 영구 원반 |1은;는; 경로에 있는 적에게 [(1930% 전투/주문력)] 의 비전 피해를 입힙니다.\n\n 돌아오는 원반을 받으면 다시 던지며 피해 흡수 보호막을 얻습니다. 최대 2번까지 투척할 수 있습니다."}
