MultiLanguageSpellData['ko'][1234357] = {name = "이 흉터가 곧 나다!", additional_info = "[q]이 흉터가 곧 나다! 등급이 5만큼 추가로 증가합니다.\n\n 이 흉터가 곧 나다!\n시전자의 지옥상흔 육체가 공격자에게 10초에 걸쳐 [((14% 전투/주문력)) * 10 / 2] 의 혼돈 피해를 입힙니다.\n\n지옥 손길 상태인 적에게는 2배의 피해를 입힙니다.\n\n 이 효과는 최대 5번까지 중첩됩니다."}
