MultiLanguageSpellData['ko'][1235963] = {name = "Mage Frostfire 11.2 Class Set 2pc", additional_info = "[q]비전, 냉기\n 유성과 서리불꽃 폭발의 공격력이 30%만큼 증가합니다. 얼음불꽃 화살의 공격력이 10%만큼 증가합니다. 유성, 서리불꽃 폭발, 얼음불꽃 화살이 작열을 부여하고 9초에 걸쳐 25%의 추가 피해를 입힙니다.\n\n화염\n 혜성 폭풍과 서리불꽃 폭발의 공격력이 15%만큼 증가합니다. 얼음불꽃 화살의 공격력이 8%만큼 증가합니다. 혜성 폭풍, 서리불꽃 폭발, 얼음불꽃 화살이 75%의 효율로 작열을 부여합니다."}
MultiLanguageSpellData['ko'][1235964] = {name = "Mage Spellslinger 11.2 Class Set 4pc", additional_info = "[q]비전\n 쇄편의 공격력이 8%만큼 증가합니다. 또한 비전 보주가 100%의 확률로 비전의 조화 중첩을 부여합니다. 최대 8번까지 중첩됩니다. 비전의 조화가 20번 중첩되면 100%의 효율로 직관력이 부여됩니다.\n\n화염\n 쇄편의 공격력이 8%만큼 증가합니다. 또한 비전 보주가 100%의 확률로 비전의 조화 중첩을 부여합니다. 최대 8번까지 중첩됩니다. 한랭 전선이 얼어붙은 구슬을 소환하면 10초 동안 주문 공격력이 8%만큼 증가합니다.\n\n냉기\n 얼어붙은 구슬이 1명 이상의 적에게 피해를 입히면 15%의 확률로 한랭 전선 중첩이 부여됩니다. 한랭 전선이 얼어붙은 구슬을 소환하면 10초 동안 주문 공격력이 8%만큼 증가합니다.\n\n(100밀리초 재사용 대기시간)"}
MultiLanguageSpellData['ko'][1235965] = {name = "Mage Sunfury 11.2 Class Set 4pc", additional_info = "[q]비전\n 불사조가 뛰어난 주문을 시전하면 다음 비전의 영혼의 지속시간이 0.5초만큼 추가로 증가합니다. 불사조가 만료되면 시전자가 추가로 강화되어 하급 시간 왜곡이 부여되고, 10초 동안 주문 공격력이 20%만큼 증가합니다.\n\n화염, 냉기\n 불사조가 뛰어난 주문을 시전하면 다음 이상 고열의 지속시간이 0.3초만큼 추가로 증가합니다. 불사조가 만료되면 시전자가 추가로 강화되어 하급 시간 왜곡이 부여되고, 10초 동안 주문 공격력이 10%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1235966] = {name = "Mage Frostfire 11.2 Class Set 4pc", additional_info = "[q]화염\n 불덩이 작렬 시전 시 20%의 확률로 혹한의 쐐기를 추가로 시전해 (주문력의 366.24%)의 냉기 피해를 입힙니다. 이 방식으로 시전된 혹한의 쐐기는 대상을 이동 불사 상태로 만들지 않습니다. 또한 혹한의 쐐기|1이;가; 작열의 효과를 받습니다.\n\n비전, 냉기\n 혹한의 쐐기 시전 시 100%의 확률로 불덩이 작렬을 추가로 시전해 (주문력의 352.5%)의 화염 피해를 입힙니다.. 또한 불덩이 작렬|1이;가; 작열의 효과를 받습니다."}
