MultiLanguageSpellData['ko'][1236332] = {name = "Druid Elune's Chosen 11.2 Class Set 2pc", additional_info = "[q]야성, 수호, 회복\n 난타의 공격력이 20%만큼 증가합니다. 난타를 사용하면 40%의 확률로 대상에게 별빛쇄도를 160%의 효율로 방출합니다.\n\n조화\n 별빛섬광의 공격력이 15%만큼 증가합니다. 별빛섬광으로 천공의 힘을 생성하면 40%의 확률로 대상에게 별빛쇄도를 45%의 효율로 방출합니다.\n\n(100밀리초 재사용 대기시간)"}
MultiLanguageSpellData['ko'][1236333] = {name = "Druid Elune's Chosen 11.2 Class Set 4pc", additional_info = "[q]야성, 수호, 회복\n 난타|1으로;로; 발사된 별빛쇄도가 적중할 때 최대 3명의 추가 대상에게 20%의 효율로 적중하고 모이는 달빛 중첩을 얻습니다. 달 광선 시전 시 모이는 달빛을 소모하여 중첩 하나당 12초 동안 공격력이 4%만큼 증가합니다.\n\n조화\n 별빛섬광|1으로;로; 발사된 별빛쇄도가 적중할 때 최대 3명의 추가 대상에게 40%의 효율로 적중하고 모이는 달빛 중첩을 얻습니다. 엘룬의 분노 또는 보름달 시전 시 모이는 달빛을 소모하여 중첩 하나당 12초 동안 공격력이 4%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1236334] = {name = "Druid Keeper of the Grove 11.2 Class Set 2pc", additional_info = "[q]조화, 야성, 수호\n 천체의 정렬 시전 시 10초 동안 드리아드의 지원을 받습니다. 드리아드는 360%의 효율로 별빛쇄도를, 800%의 효율로 별똥별을 시전합니다.\n\n회복\n 화신: 생명의 나무 또는 영혼 소집 시전 시 5초 동안 드리아드의 지원을 받습니다. 드리아드는 50%의 효율로 평온을 시전하며, 생명력이 가장 낮은 아군에게 200%의 효율로 재생을 즉시 시전합니다."}
MultiLanguageSpellData['ko'][1236336] = {name = "Druid Keeper of the Grove 11.2 Class Set 4pc", additional_info = "[q]조화, 야성, 수호\n 드리아드가 사라지면 다음 2회의 별빛쇄도|1이;가; 활성화된 동안 입힌 피해의 3%에 해당하는 피해를 추가로 입히거나 생명력을 회복시키며, 피해의 10%만큼 주위의 적을 치유하거나 피해를 입힙니다. 5명을 초과하는 대상에게는 효과가 감소합니다.\n\n회복\n 드리아드가 사라지면 다음 2회의 신속한 치유|1이;가; 활성화된 동안 치유량의 5%에 해당하는 피해를 추가로 입히거나 생명력을 회복시키며, 치유량의 25%만큼 주위의 아군을 치유하거나 피해를 입힙니다. 5명을 초과하는 대상에게는 효과가 감소합니다."}
MultiLanguageSpellData['ko'][1236337] = {name = "Druid Wildstalker 11.2 Class Set 2pc", additional_info = "[q]조화, 수호, 회복\n 공생체 꽃의 성장 속도가 45%만큼 빨라집니다. 번뜩임의 효과를 받아 재생을 시전하면 공생체 꽃이 주위의 유효한 아군 최대 2명에게 자라납니다.\n\n야성\n 피바라미 덩굴의 성장 속도가 40%만큼 빨라집니다. 호랑이의 분노 사용 시 피바라미 덩굴이 주위의 유효한 적 최대 3명에게 자라납니다."}
MultiLanguageSpellData['ko'][1236338] = {name = "Druid Wildstalker 11.2 Class Set 4pc", additional_info = "[q]조화, 수호, 회복\n 공생체 꽃|1이;가; 2초마다 35%의 확률로 폭발하는 성장물을 100%의 효율로 발동시킵니다. 아군에게 부여된 공생체 꽃 중첩 하나당 폭발하는 성장물의 치유량이 30%만큼 증가합니다.\n\n야성\n 피바라미 덩굴|1이;가; 2초마다 20%의 확률로 폭발하는 성장물을 100%의 효율로 발동시킵니다. 적에게 부여된 피바라미 덩굴 중첩 하나당 폭발하는 성장물의 공격력이 40%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1236342] = {name = "공격 준비", additional_info = "즉시\n[q]조화, 수호, 회복\n찢어발기기 사용 시 40%의 확률로 4초 후에 대상에게 다시 찢어발기기를 사용해 60%의 효율을 발휘하도록 합니다.\n\n야성\n찢어발기기 사용 시 40%의 확률로 4초 후에 대상에게 다시 찢어발기기를 사용해 초기 위력의 100%에 해당하는 효과를 발휘하도록 합니다."}
