MultiLanguageSpellData['ko'][1236355] = {name = "Death Knight Rider of the Apocalypse 11.2 Class Set 2pc", additional_info = "[q]혈기, 부정\n 대재앙 사용 시 10초 동안 화이트메인을 소환합니다. 화이트메인의 불사의 역병의 공격력이 20%만큼 증가하고, 전이될 때 1명의 추가 대상을 감염시킵니다. 또한 화이트메인의 죽음의 고리가 35%의 추가 피해를 입힙니다.\n\n냉기\n 얼음 기둥 사용 시 10초 동안 트롤베인을 소환합니다. 트롤베인의 서늘한 격노의 공격력이 20%만큼 증가하고, 트롤베인의 절멸이 15%의 추가 피해를 입힙니다."}
MultiLanguageSpellData['ko'][1236356] = {name = "Death Knight Rider of the Apocalypse 11.2 Class Set 4pc", additional_info = "[q]냉기\n 절멸 또는 서리낫 시전 시 트롤베인이 함께 절멸 또는 서리낫을 100%의 효율로 시전합니다. 시전자의 절멸은 트롤베인의 서늘한 격노에 영향을 받는 대상에게 20%의 추가 피해를 입힙니다.\n\n혈기, 부정\n 죽음의 고리 또는 전염병 시전 시 화이트메인이 함께 죽음의 고리 또는 전염병을 125%의 효율로 시전합니다. 시전자의 죽음의 고리는 화이트메인의 불사의 역병에 영향을 받는 대상에게 40%의 추가 피해를 입힙니다.\n\n(500밀리초 재사용 대기시간)"}
