MultiLanguageSpellData['ko'][1236360] = {name = "Demon Hunter Aldrachi Reaver 11.2 Class Set 4pc", additional_info = "[q]복수\n 절단 사용 후 영혼 베어내기|1을;를; 시전하면 알드라치의 격노에 의해 추가로 강화되어, 베기 횟수가 12번으로 증가합니다.\n\n 파괴자의 징표가 최대 2번까지 중첩되며, 영혼 베어내기 사용 후 절단 시전 시 효과가 추가로 강화되어 일반 지속시간의 100%에 해당하는 추가 중첩을 부여합니다.\n\n파멸\n 혼돈의 일격 사용 후 칼춤|1을;를; 시전하면 알드라치의 격노에 의해 추가로 강화되어, 베기 횟수가 12번으로 증가합니다.\n\n 파괴자의 징표가 최대 2번까지 중첩되며, 칼춤 사용 후 혼돈의 일격 시전 시 효과가 추가로 강화되어 일반 지속시간의 100%에 해당하는 추가 중첩을 부여합니다."}
MultiLanguageSpellData['ko'][1236361] = {name = "Demon Hunter Fel-Scarred 11.2 Class Set 2pc", additional_info = "[q]복수\n 활성화된 동안 제물의 오라의 공격력이 30%만큼, 영혼 베어내기의 공격력이 20%만큼 증가합니다.\n\n파멸\n 활성화된 동안 제물의 오라의 공격력이 30%만큼, 혼돈의 일격의 공격력이 20%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1236362] = {name = "Demon Hunter Fel-Scarred 11.2 Class Set 4pc", additional_info = "[q]파멸\n 악마로 변신 시 즉시 악마쇄도가 발동하고 악마 영혼 파편을 떼어내 10초 동안 공격력이 20%만큼 증가합니다.\n\n복수\n 악마로 변신 시 즉시 악마쇄도가 발동하고 악마 영혼 파편을 떼어내 15초 동안 공격력이 20%만큼 증가합니다.\n\n(100밀리초 재사용 대기시간)"}
MultiLanguageSpellData['ko'][1236364] = {name = "Evoker Flameshaper 11.2 Class Set 2pc", additional_info = "[q]업화가 내면의 불꽃을 피워 공격 및 치유 지속 효과가 25%만큼 증가하고 12초 동안 정수 폭발이 발동할 확률이 50%만큼 증가합니다. 최대 2번까지 중첩됩니다. 여러 번 사용 시 효과가 중첩됩니다."}
MultiLanguageSpellData['ko'][1236365] = {name = "Evoker Flameshaper 11.2 Class Set 4pc", additional_info = "[q]보존, 증강\n 내면의 불꽃의 지속시간 동안 정수 폭발을 소모하면 대상에게 정수 폭탄을 발사해 주위의 아군을 (주문력의 250%)만큼 치유합니다. 5명을 초과하는 대상에게는 효과가 감소합니다.\n\n황폐\n 내면의 불꽃의 지속시간 동안 정수 폭발을 소모하면 대상에게 정수 폭탄을 발사해 주위의 적에게 (주문력의 371%)의 비전 피해를 입힙니다. 5명을 초과하는 대상에게는 효과가 감소합니다."}
MultiLanguageSpellData['ko'][1236366] = {name = "Evoker Scalecommander 11.2 Class Set 2pc", additional_info = "[q]증강\n 깊은 숨결 의 비행 지속시간 동안, 그리고 효과가 끝난 후 20초 동안 드랙티르 2명으로 구성된 편대를 지휘하여 대상을 파열 및 기염으로 공격하게 합니다.\n\n황폐, 보존\n 깊은 숨결의 비행 지속시간 동안, 그리고 효과가 끝난 후 10초 동안 드랙티르 2명으로 구성된 편대를 지휘하여 대상을 파열 및 기염으로 공격하게 합니다."}
MultiLanguageSpellData['ko'][1236367] = {name = "Evoker Scalecommander 11.2 Class Set 4pc", additional_info = "[q]증강\n 편대가 활성화된 동안 대규모 분출|1이;가; 최대 2명의 추가 대상을 가격합니다. 또한 편대가 10초 동안 추가로 전투를 돕습니다.\n\n보존\n 편대가 활성화된 동안 대규모 분출|1이;가; 최대 2명의 추가 대상을 가격합니다. 또한 편대가 5초 동안 추가로 전투를 돕습니다.\n\n황폐\n 편대가 활성화된 동안 대규모 파열|1이;가; 최대 2명의 추가 대상을 가격합니다. 또한 편대가 5초 동안 추가로 전투를 돕습니다."}
