MultiLanguageSpellData['ko'][1236369] = {name = "Evoker Chronowarden 11.2 Class Set 4pc", additional_info = "[q]시간의 폭발 발동 시 시간의 불꽃이 2명의 추가 대상을 공격해 반복해서 15%의 추가 피해를 입히거나 생명력을 회복시킵니다. 최대 피해량 또는 치유량은 [(주문력 * 4.5) * (1 + 유연성)]입니다. 또한, 정수 능력의 공격력과 치유량이 30%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1236370] = {name = "Hunter Dark Ranger 11.2 Class Set 2pc", additional_info = "[q]야수\n 검은 화살의 공격력이 10%만큼, 황폐의 화약의 공격력이 20%만큼 증가합니다. 야생의 부름의 재사용 대기시간이 60초만큼 감소합니다.\n\n사격, 생존\n 검은 화살의 공격력이 10%만큼, 황폐의 화약의 공격력이 20%만큼 증가합니다. 정조준의 재사용 대기시간이 30초만큼 감소합니다."}
MultiLanguageSpellData['ko'][1236371] = {name = "Hunter Dark Ranger 11.2 Class Set 4pc", additional_info = "[q]야수, 사격, 생존\n 부패의 사격의 검은 화살 공격력이 50%만큼 증가합니다. 죽음의 강타를 소모하면 50%의 확률로 다음 부패의 사격의 지속시간 동안 모든 검은 화살 연사가 1발의 검은 화살을 추가로 발사합니다."}
MultiLanguageSpellData['ko'][1236372] = {name = "Hunter Pack Leader 11.2 Class Set 2pc", additional_info = "[q]사격, 생존\n 야수의 공격력이 15%만큼, 맹수의 공격력이 15%만큼 증가합니다. 맹수 소환 시 소환된 맹수에 따라 8초 동안 가속이나 특화, 치명타 및 극대화율이 6%만큼 증가합니다.\n\n야수\n 야수의 공격력이 5%만큼, 맹수의 공격력이 15%만큼 증가합니다. 맹수 소환 시 소환된 맹수에 따라 8초 동안 가속이나 특화, 치명타 및 극대화율이 6%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1236373] = {name = "Hunter Pack Leader 11.2 Class Set 4pc", additional_info = "[q]솔선수범의 효과를 받는 동안 맹수를 소환하면 주위의 야생동물이 자극을 받아 쇄도를 시작해, 대상에게 돌진해 최대 8명의 적에게 7초에 걸쳐 [(전투력의 300%) * 9]의 물리 피해를 입힙니다."}
MultiLanguageSpellData['ko'][1236374] = {name = "Hunter Sentinel 11.2 Class Set 2pc", additional_info = "[q]사격\n 속사의 공격력이 25%만큼 증가합니다. 달의 폭풍의 효과가 사라지면 엘룬의 은혜를 얻어 다음 2회의 조준 사격|1이;가; 비전 피해를 입히고 공격력이 10%만큼 증가합니다.\n\n야수, 생존\n 야생불 폭탄의 공격력이 10%만큼 증가합니다. 달의 폭풍의 효과가 사라지면 엘룬의 은혜를 얻어 다음 2회의 야생불 폭탄|1이;가; 비전 피해를 입히고 최초 공격력이 150%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1236375] = {name = "Hunter Sentinel 11.2 Class Set 4pc", additional_info = "[q]사격\n 파수꾼의 공격력이 18%만큼 증가합니다. 또한 달의 폭풍의 지속시간 동안 엘룬의 은혜가 100%의 효율로 활성화됩니다.\n\n야수, 생존\n 파수꾼의 공격력이 20%만큼 증가합니다. 또한 달의 폭풍의 지속시간 동안 엘룬의 은혜가 100%의 효율로 활성화됩니다."}
