MultiLanguageSpellData['ko'][1236377] = {name = "Monk Master of Harmony 11.2 Class Set 2pc", additional_info = "[q]양조\n 활력을 얻으면 다음 범의 장풍이 조화의 쇄도를 방출해 대상과 주위의 다른 적에게 [180 * (주문력의 400%) / 100]의 자연 피해를 나누어 입히고 최대 5명의 부상당한 아군을 [20 * (주문력의 500%) / 100]만큼 치유할 확률이 증가합니다.\n\n풍운, 운무\n 활력을 얻으면 다음 범의 장풍이 조화의 쇄도를 방출해 대상과 주위의 다른 적에게 [20 * (주문력의 400%) / 100]의 자연 피해를 나누어 입히고 최대 5명의 부상당한 아군을 [90 * (주문력의 500%) / 100]만큼 치유할 확률이 증가합니다."}
MultiLanguageSpellData['ko'][1236378] = {name = "Monk Master of Harmony 11.2 Class Set 4pc", additional_info = "[q]풍운, 운무\n 집중의 천둥 차 시전 시 다음 2회 동안 사용하는 범의 장풍이 조화의 쇄도를 발동시킵니다.\n\n양조\n 시전 시 다음 2회 동안 사용하는 범의 장풍이 조화의 쇄도를 발동시킵니다."}
MultiLanguageSpellData['ko'][1236379] = {name = "Monk Shado-Pan 11.2 Class Set 2pc", additional_info = "[q]양조\n 질풍격이 10%의 추가 피해를 입힙니다. 또한 질서의 무기 활성화 시 즉시 질풍격 10중첩이 부여되고 다음 공격 시 70%의 효율로 발동합니다.\n\n풍운, 운무\n 질풍격이 20%의 추가 피해를 입힙니다. 또한 폭풍과 대지와 불 활성화 시 즉시 질풍격 10중첩이 부여되고 다음 공격 시 70%의 효율로 발동합니다."}
MultiLanguageSpellData['ko'][1236380] = {name = "Monk Shado-Pan 11.2 Class Set 4pc", additional_info = "[q]양조, 운무\n 질서의 무기의 지속시간 동안 질풍격 충전물 생성 속도가 50%만큼 증가하고 150의 기력을 소모할 때마다 질풍격이 발동합니다.\n\n풍운\n 폭풍과 대지와 불의 지속시간 동안 질풍격 충전물 생성 속도가 50%만큼 증가하고 150의 기력을 소모할 때마다 질풍격이 발동합니다."}
MultiLanguageSpellData['ko'][1236381] = {name = "Monk Conduit of the Celestials 11.2 Class Set 2pc", additional_info = "[q]풍운\n 날카로운 바람 시전 시 옥룡의 마음이 4초 동안 100%의 효율로 발동합니다.\n\n양조, 운무\n 집중의 천둥 차 시전 시 옥룡의 마음이 8초 동안 100%의 효율로 발동합니다.\n\n(1초 재사용 대기시간)"}
