MultiLanguageSpellData['ko'][1236391] = {name = "Paladin Templar 11.2 Class Set 2pc", additional_info = "[q]최고천의 망치의 치명타 및 극대화 피해가 20%만큼 증가합니다. 또한 치명타 및 극대화로 적중하면 50%의 확률로 구세의 빛 중첩이 추가로 부여됩니다.\n(효과 발동 확률: 50%)"}
MultiLanguageSpellData['ko'][1236392] = {name = "Paladin Templar 11.2 Class Set 4pc", additional_info = "[q]신성, 보호\n 빛의 망치가 주 대상에게 35%의 추가 피해를 입히고 3명의 추가 부가 대상을 가격합니다. 또한 티르의 눈 사용 후에는 1회 추가로 시전할 수 있습니다.\n\n징벌\n 빛의 망치가 주 대상에게 35%의 추가 피해를 입히고 3명의 추가 부가 대상을 가격합니다. 또한 파멸의 재 사용 후에는 1회 추가로 시전할 수 있습니다."}
