MultiLanguageSpellData['ko'][1236395] = {name = "Priest Oracle 11.2 Class Set 4pc", additional_info = "[q]경건의 흉조 또는 위안의 흉조 시전 시 100%의 효율로 통찰의 흉조 2중첩이 부여됩니다. 통찰의 흉조 중첩을 소모하면 10초 동안 가속이 1.0%만큼 증가합니다. 여러 번 사용 시 효과가 중첩됩니다."}
MultiLanguageSpellData['ko'][1236396] = {name = "Priest Voidweaver 11.2 Class Set 2pc", additional_info = "[q]수양\n 공허의 폭발 및 회개의 공격력이 30%만큼 증가합니다. 공허의 폭발의 시전 시간은 20%만큼 감소합니다.\n\n신성\n 공허의 폭발의 공격력이 30%만큼 증가합니다. 공허의 폭발의 시전 시간은 20%만큼 감소합니다.\n\n암흑\n 공허의 폭발의 공격력이 30%만큼 증가합니다. 공허의 폭발의 시전 시간은 20%만큼 감소합니다. 공허의 폭발의 재사용 대기시간이 50%만큼 감소합니다."}
MultiLanguageSpellData['ko'][1236397] = {name = "Priest Voidweaver 11.2 Class Set 4pc", additional_info = "[q]신성, 암흑\n 공허의 폭발 시전 시 혼돈의 균열이 커집니다. 또한 공허 붕괴 시전 시 혼돈의 균열이 10%의 추가 피해를 입히며, 붕괴하는 혼돈의 균열의 크기에 따라 다음 공허의 격류의 공격력이 최대 200%만큼 증가합니다.\n\n수양\n 공허의 폭발 시전 시 혼돈의 균열이 커집니다. 또한 공허 붕괴 시전 시 혼돈의 균열이 10%의 추가 피해를 입히며, 붕괴하는 혼돈의 균열의 크기에 따라 다음 정신 분열의 공격력이 최대 200%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1236398] = {name = "Priest Archon 11.2 Class Set 2pc", additional_info = "[q]암흑\n 후광이 5초에 걸쳐 10의 광기를 추가로 생성합니다. 또한 공명하는 마력이 파멸의 역병의 공격력을 5.0%만큼 증가시킵니다.\n\n수양, 신성\n 후광이 빛의 권능: 평온 및 빛의 권능: 신성화의 재사용 대기시간을 5초만큼 감소시킵니다. 또한 공명하는 마력이 빛의 권능의 치유량을 5.0%만큼 증가시킵니다."}
