MultiLanguageSpellData['ko'][1236408] = {name = "Shaman Stormbringer 11.2 Class Set 2pc", additional_info = "[q]고양, 복원\n 승천 사용 시 100%의 확률로 폭풍이 1회 충전됩니다. 또한 깨어나는 폭풍을 8회 시전할 때마다 6.0초 동안 승천이 활성화됩니다.\n\n정기\n 승천 사용 시 100%의 확률로 폭풍이 1회 충전됩니다. 또한 깨어나는 폭풍을 9회 시전할 때마다 6.0초 동안 승천이 활성화됩니다.\n\n(100밀리초 재사용 대기시간)"}
MultiLanguageSpellData['ko'][1236409] = {name = "Shaman Stormbringer 11.2 Class Set 4pc", additional_info = "[q]정기, 복원\n 자연 공격력이 3.0%만큼 증가하고, 승천 사용 시 다음 2회의 폭풍이 강화되어 하늘에 태풍을 응집시킵니다. 태풍은 1.5초 후에 주 대상에게 (주문력의 960%)의 자연 피해를 입히고 주위의 적에게는 감소된 피해를 입힙니다.\n\n고양\n 자연 공격력이 5.0%만큼 증가하고, 승천 사용 시 다음 2회의 폭풍이 강화되어 하늘에 태풍을 응집시킵니다. 태풍은 1.5초 후에 주 대상에게 (전투력의 400%)의 자연 피해를 입히고 주위의 적에게는 감소된 피해를 입힙니다.\n\n(100밀리초 재사용 대기시간)"}
MultiLanguageSpellData['ko'][1236410] = {name = "Shaman Totemic 11.2 Class Set 2pc", additional_info = "[q]고양\n 휘몰아치는 정기 티끌을 모두 소모하면 그 위치에 쇄도하는 토템이 200%의 효율로 태고의 폭풍을 시전합니다.\n\n정기, 복원\n 휘몰아치는 정기 티끌을 모두 소모하면 쇄도하는 토템의 위치에 200%의 효율로 폭우를 시전합니다."}
MultiLanguageSpellData['ko'][1236411] = {name = "Shaman Totemic 11.2 Class Set 4pc", additional_info = "[q]고양\n 태고의 폭풍 시전 후 다음 용암 채찍 또는 불꽃 회오리|1을;를; 150%의 효율로 다시 시전합니다.\n\n정기, 복원\n 폭우 시전 후 다음 연쇄 치유, 치유의 물결 또는 치유의 파도|1을;를; 150%의 효율로 다시 시전합니다.\n\n(500밀리초 재사용 대기시간)"}
