MultiLanguageSpellData['ko'][1249462] = {name = "합의서: 조 중개단", additional_info = "즉시\n[q]조 중개단과 협상을 통해 해당 중개단의 소속을 자칭할 권리를 얻습니다. 일주일 동안만 말이죠.\n\n 전투부대 계약\n 합의는 일주일에 한 중개단하고만 맺을 수 있습니다. 이 효과는 전투부대와 공유됩니다."}
MultiLanguageSpellData['ko'][1249463] = {name = "[q3]합의서: 조 중개단", additional_info = "3.5 초 주문 시전 시간\n재료:\n새로운 양피지 , 마나단조 도구 , 햇볕 잉크 (25)\n마나괴철로 파괴단\n영예:\n8\n지역:\n어둠 거점\n\n[q3]합의서: 조 중개단\n[q2]사용 효과: 조 중개단과 협상을 통해 해당 중개단의 소속을 자칭할 권리를 얻습니다. 일주일 동안만 말이죠.\n\n 전투부대 계약\n 합의는 일주일에 한 중개단하고만 맺을 수 있습니다. 이 효과는 전투부대와 공유됩니다.\n70\n[q]\"어느 한 중개단에 대한 전투부대의 충성을 맹세하는 단기 \"계약서\"입니다. 주문각인사가 만듭니다.\""}
MultiLanguageSpellData['ko'][1249464] = {name = "엘룬의 은혜", additional_info = "즉시\n[q]사격\n속사의 공격력이 25%만큼 증가합니다. 달의 폭풍의 효과가 사라지면 엘룬의 은혜를 얻어 다음 2회의 조준 사격|1이;가; 비전 피해를 입히고 공격력이 10%만큼 증가합니다.\n\n야수, 생존\n야생불 폭탄의 공격력이 10%만큼 증가합니다. 달의 폭풍의 효과가 사라지면 엘룬의 은혜를 얻어 다음 2회의 야생불 폭탄|1이;가; 비전 피해를 입히고 최초 공격력이 150%만큼 증가합니다."}
MultiLanguageSpellData['ko'][1249465] = {name = "합의서: 바 중개단", additional_info = "즉시\n[q]바 중개단과 협상을 통해 해당 중개단의 소속을 자칭할 권리를 얻습니다. 일주일 동안만 말이죠.\n\n 전투부대 계약\n 합의는 일주일에 한 중개단하고만 맺을 수 있습니다. 이 효과는 전투부대와 공유됩니다."}
MultiLanguageSpellData['ko'][1249466] = {name = "[q3]합의서: 바 중개단", additional_info = "3.5 초 주문 시전 시간\n재료:\n새로운 양피지 , 마나단조 도구 , 햇볕 잉크 (25)\n마나괴철로 파괴단\n영예:\n8\n지역:\n어둠 거점\n\n[q3]합의서: 바 중개단\n[q2]사용 효과: 바 중개단과 협상을 통해 해당 중개단의 소속을 자칭할 권리를 얻습니다. 일주일 동안만 말이죠.\n\n 전투부대 계약\n 합의는 일주일에 한 중개단하고만 맺을 수 있습니다. 이 효과는 전투부대와 공유됩니다.\n70\n[q]\"어느 한 중개단에 대한 전투부대의 충성을 맹세하는 단기 \"계약서\"입니다. 주문각인사가 만듭니다.\""}
