MultiLanguageSpellData['ko'][1250285] = {name = "상어이빨 마루뿔", additional_info = "1.5 초 주문 시전 시간\n[q]탈것에 올라타거나 내립니다.\n[q]\"마루뿔은 해초를 뜯어 먹으려 해안으로 이끌리는 경우가 많습니다. 험한 바다 생물들들을 헤치고 이곳까지 온 개체들은 진정한 칼루아크라 불릴 자격이 있습니다.\"\n교역소"}
