MultiLanguageSpellData['ko'][1250288] = {name = "암반걸음 마루뿔", additional_info = "1.5 초 주문 시전 시간\n[q]탈것에 올라타거나 내립니다.\n[q]\"투스카르는 높은산에서 쉽게 볼 수 없는 존재지만, 마루뿔은 해안가의 희귀한 먹잇감을 찾아 종종 바닷가로 내려옵니다.\"\n교역소"}
MultiLanguageSpellData['ko'][1250314] = {name = "환영꽃", additional_info = "5 야드 사정거리\n2.5 초 주문 시전 시간\n[q]환영꽃은 크아레쉬 토종 식물의 잔류 마력으로, 알가르 제작법에 통합하는 건 불가능합니다.\n\n 자원 시장에서 환영꽃을 알가르 재료로 교환할 수 있습니다. 교환 가격은 매일 달라집니다. 제일 저렴한 가격에 상품을 구매하려면 인내심이 필요할 겁니다!"}
MultiLanguageSpellData['ko'][1250317] = {name = "무성한 환영꽃", additional_info = "5 야드 사정거리\n2.5 초 주문 시전 시간\n[q]환영꽃은 크아레쉬 토종 식물의 잔류 마력으로, 알가르 제작법에 통합하는 건 불가능합니다.\n\n 자원 시장에서 환영꽃을 알가르 재료로 교환할 수 있습니다. 교환 가격은 매일 달라집니다. 제일 저렴한 가격에 상품을 구매하려면 인내심이 필요할 겁니다!\n\n 예상보다 훨씬 크게 자라는 환영꽃이 발견되고 있습니다. 환영꽃은 본래 무자비한 크아레쉬 사막의 황무지에서 살아남은 몇 안 되는 식물 중 하나로, 길들지 않은 숲의 푸른 환경에서는 훨씬 크게 번성했던 것으로 알려져 있습니다."}
