MultiLanguageSpellData['ko'][1250356] = {name = "풍부한 황폐 광맥", additional_info = "5 야드 사정거리\n2.5 초 주문 시전 시간\n[q]크아레쉬에서 두둑한 밑천을 잡으려고 드는 광부들을 기다리는 건 황폐해진 세상의 잔재입니다. 이 광물은 알가르 제작에 사용할 수 없지만, 타자베쉬 주민들은 이런 잔해에서도 나름의 가치를 알아볼지도 모릅니다.\n\n간혹 땅속에서 비정상적으로 커다란 광맥이 나타나곤 합니다. 일용할 양식을 찾아 헤매는 광부에게 더없이 반가운 풍경이죠."}
