MultiLanguageSpellData['ko'][1251408] = {name = "구원자의 심판", additional_info = "[q]유물 능력\n\n 15초 동안 빛벼림 상태가 됩니다. 대상을 추적하는 천상의 빛줄기를 불러 내려 대상 지역 안에 있는 적에게는 최대 [(200% 전투/주문력)] 의 신성 피해를 입히고 아군 대상은 10초 동안 0.5초마다 [(141% 전투/주문력)] 만큼 치유합니다. 5명을 초과하는 대상에게는 입히는 피해와 치유 효과가 감소합니다.\n\n빛벼림\n유물의 다른 빛 속성을 강화합니다."}
