MultiLanguageSpellData['ko'][1252190] = {name = "발키르의 비행", additional_info = "[q]구원자의 심판 |1이;가; 최대 5명의 주위 아군에게 축복을 내려 8초 동안 발키르의 보호를 받게 합니다.\n\n 보호받는 동안 죽음에 이르는 공격을 받으면 발키르가 개입하여 대상을 완전히 회복시킵니다. 같은 대상에게 8분에 한 번씩만 발동합니다."}
